import 'package:flutter/material.dart';

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      debugShowCheckedModeBanner: false,
      home: GalleryPage(),
    );
  }
}

class GalleryPage extends StatelessWidget {
  // Image List
  List<String> images = [
    'data:image/jpeg;base64,',
    'data:image/jpeg;base64,',
    'data:image/jpeg;base64,',
    'https://www.google.com/imgres?q=strawberry%20chocolate%20waffle%20image&imgurl=https%3A%2F%2Fneighborfoodblog.com%2Fwp-content%2Fuploads%2F2013%2F02%2Fwaffle-with-chocolate-8.jpg&imgrefurl=https%3A%2F%2Fneighborfoodblog.com%2Fdouble-chocolate-waffles-with-fresh-strawberries-and-whipped-cream%2F&docid=MpPzqevKDAon-M&tbnid=8waGNooCkjRsBM&vet=12ahUKEwjc-oH4rcWUAxVdd2wGHfckDFEQnPAOegQIGhAB..i&w=1200&h=1798&hcb=2&ved=2ahUKEwjc-oH4rcWUAxVdd2wGHfckDFEQnPAOegQIGhAB',
    'data:image/jpeg;base64,',
    "https://picsum.photos/200?5",
    "https://picsum.photos/200?6",
  ];

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text("Image Gallery"),
      ),
      body: GridView.builder(
        itemCount: images.length,
        gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
          crossAxisCount: 2,
          crossAxisSpacing: 10,
          mainAxisSpacing: 10,
        ),
        itemBuilder: (context, index) {
          return Padding(
            padding: EdgeInsets.all(8),
            child: Image.network(
              images[index],
              fit: BoxFit.cover,
            ),
          );
        },
      ),
    );
  }
}
